  'api.ref.random.desc':        { en: 'Returns an array of 1–50 random quotes. All parameters are optional — call with no query string to get a single random quote.', es: 'Devuelve un array de 1–50 citas aleatorias. Todos los parámetros son opcionales — llama sin query string para obtener una sola cita aleatoria.' },
