  'api.res.faq.desc':  { en: 'Common questions and answers about using our API.', es: 'Preguntas y respuestas comunes sobre el uso de nuestra API.' },
  'api.res.general':   { en: 'General Questions',  es: 'Preguntas Generales'  },
  'api.res.technical': { en: 'Technical Questions', es: 'Preguntas Técnicas'   },
  'api.res.billing':   { en: 'Billing & Plans',     es: 'Facturación y Planes' },
  'api.res.faq.rate-limits.q': { en: 'What are the rate limits?', es: '¿Cuáles son los límites de tasa?' },
  'api.res.faq.rate-limits.a': { en: 'Rate limits depend on your plan: Free 100 req/hr, Basic 1 000 req/hr, Pro 10 000 req/hr, Enterprise custom limits. Rate limit headers are included in every response.', es: 'Los límites de tasa dependen de tu plan: Free 100 req/hr, Basic 1 000 req/hr, Pro 10 000 req/hr, Enterprise límites personalizados. Las cabeceras de límite de tasa se incluyen en cada respuesta.' },
  'api.res.faq.auth.q': { en: 'How do I handle authentication securely?', es: '¿Cómo manejo la autenticación de forma segura?' },
  'api.res.faq.auth.a': { en: 'Never expose API keys in client-side code. Use environment variables, rotate keys every 90 days, and implement IP whitelisting. For frontend apps, create a backend proxy that handles API authentication.', es: 'Nunca expongas claves de API en código del cliente. Usa variables de entorno, rota claves cada 90 días e implementa lista blanca de IPs. Para apps frontend, crea un proxy backend que gestione la autenticación de API.' },
  'api.res.faq.formats.q': { en: 'What data formats are supported?', es: '¿Qué formatos de datos son compatibles?' },
  'api.res.faq.formats.a': { en: 'The API exclusively uses JSON (UTF-8, RFC 7159). All endpoints accept and return application/json.', es: 'La API usa exclusivamente JSON (UTF-8, RFC 7159). Todos los endpoints aceptan y devuelven application/json.' },
  'api.res.faq.pagination.q': { en: 'How do I paginate through large result sets?', es: '¿Cómo pagino a través de grandes conjuntos de resultados?' },
  'api.res.faq.pagination.a': { en: 'The response includes pagination.has_more to detect if more pages exist.', es: 'La respuesta incluye pagination.has_more para detectar si existen más páginas.' },
  'api.res.faq.webhooks.q': { en: 'Can I use webhooks for real-time notifications?', es: '¿Puedo usar webhooks para notificaciones en tiempo real?' },
  'api.res.faq.webhooks.a': { en: 'Yes! Webhooks are available for Pro and Enterprise plans. Configure them in your dashboard under "API Settings".', es: '¡Sí! Los webhooks están disponibles para los planes Pro y Enterprise. Configúralos en tu panel en "Configuración de API".' },
  'api.res.faq.versioning.q': { en: 'Is there API versioning?', es: '¿Hay versionado de API?' },
  'api.res.faq.versioning.a': { en: 'Yes, URL-based versioning (/v1/). We maintain backwards compatibility for at least 12 months and announce breaking changes in advance.', es: 'Sí, versionado basado en URL (/v1/). Mantenemos compatibilidad hacia atrás durante al menos 12 meses y anunciamos cambios incompatibles con anticipación.' },
  'api.res.faq.usage.q': { en: 'How is API usage calculated?', es: '¿Cómo se calcula el uso de la API?' },
  'api.res.faq.usage.a': { en: 'Each successful (2xx) request counts toward your quota. Failed requests (4xx/5xx) don\'t count. Usage resets monthly on your billing cycle date.', es: 'Cada solicitud exitosa (2xx) cuenta hacia tu cuota. Las solicitudes fallidas (4xx/5xx) no cuentan. El uso se restablece mensualmente en la fecha de tu ciclo de facturación.' },
  'api.res.faq.plans.q': { en: 'Can I upgrade or downgrade my plan?', es: '¿Puedo mejorar o degradar mi plan?' },
  'api.res.faq.plans.a': { en: 'Yes. Upgrades take effect immediately; downgrades take effect at the next billing cycle. No penalties for plan changes.', es: 'Sí. Las mejoras tienen efecto inmediato; las degradaciones tienen efecto al siguiente ciclo de facturación. Sin penalizaciones por cambios de plan.' },

